// one open contract — triggers/runtimes/nodes are just data files
export interface ModuleDescriptor { kind: ModuleKind; id: string; /* … */ }

// generic resolver: back-edge throws instead of hanging
const out = new Set<string>(), onPath = new Set<string>();
const visit = (id: string) => {
  if (out.has(id)) return;
  const m = this.mods.get(id);
  if (onPath.has(id)) throw new Error(`Dependency cycle at "${id}".`);
  onPath.add(id);
  for (const d of m.dependencies) visit(d);
  onPath.delete(id); out.add(id);
};

